// WF_CHANNEL_COMPARE — Validate payload, auth check.

const raw = $input.first().json;
const payload = raw.body || raw;

const analysisGroupId = (payload.analysis_group_id || '').trim();

if (!analysisGroupId) {
  return [{ json: { success: false, error: 'analysis_group_id is required', http_status: 400 } }];
}

return [{ json: {
  success: true,
  analysis_group_id: analysisGroupId,
  http_status: 202
} }];

// Fetch all completed analyses for this group. Exit if fewer than 2.

const data = $input.first().json;
if (!data.success) return [];

const groupId = data.analysis_group_id;
const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  const url = `${supabaseUrl}/rest/v1/channel_analyses?analysis_group_id=eq.${groupId}&status=eq.completed&select=*`;
  const res = await fetch(url, { method: 'GET', headers: sbHeaders });
  if (!res.ok) {
    const errText = await res.text();
    return [{ json: { ...data, failed: true, error: `Fetch analyses failed: HTTP ${res.status}: ${errText.slice(0, 200)}` } }];
  }
  const analyses = await res.json();
  if (!Array.isArray(analyses) || analyses.length < 2) {
    // Log and exit — not enough analyses to compare
    try {
      await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
        method: 'POST',
        headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
        body: JSON.stringify({
          project_id: null, topic_id: null, stage: 'channel_compare',
          scene_number: null, action: 'skipped_insufficient_analyses',
          status: 'skipped', duration_ms: 0, cost_usd: 0, retry_count: 0
        })
      });
    } catch (_) {}
    return [];
  }
  return [{ json: { ...data, analyses, analysis_count: analyses.length, failed: false } }];
} catch (e) {
  return [{ json: { ...data, failed: true, error: `Exception: ${e.message}` } }];
}

// Send all completed analyses to Claude Opus 4.6 for competitive landscape comparison.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const analyses = data.analyses || [];
const anthropicKey = $env.ANTHROPIC_API_KEY;
const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

const sleep = (ms) => new Promise(r => setTimeout(r, ms));

// Build channel summaries for Claude
const channelBlocks = analyses.map((a, i) => {
  const topVideos = (a.top_videos || []).slice(0, 10).map((v, vi) =>
    `  ${vi + 1}. "${v.title}" — ${(v.views || 0).toLocaleString()} views, outlier: ${v.outlier_score || 0}x`
  ).join('\n');

  const blueOcean = (a.blue_ocean_opportunities || []).map(o =>
    `  - ${o.opportunity} (${o.difficulty || 'unknown'} difficulty): ${o.rationale || ''}`
  ).join('\n');

  const saturation = (a.content_saturation_map || []).map(s =>
    `  - ${s.topic}: ${s.saturation} (${s.video_count_seen || 0} videos seen)`
  ).join('\n');

  return `=== CHANNEL ${i + 1}: ${a.channel_name} ===
URL: ${a.channel_url || 'N/A'}
Subscribers: ${(a.subscriber_count || 0).toLocaleString()}
Total Views: ${(a.total_view_count || 0).toLocaleString()}
Videos: ${a.video_count || 0}
Avg Views/Video: ${(a.avg_views_per_video || 0).toLocaleString()}
Median Views/Video: ${(a.median_views_per_video || 0).toLocaleString()}
Upload Frequency: every ${a.upload_frequency_days || '?'} days
Growth: ${a.growth_trajectory || 'unknown'}
Content Style: ${a.content_style || 'unknown'}
Target Audience: ${a.target_audience_description || 'unknown'}
Primary Topics: ${(a.primary_topics || []).join(', ')}
Strengths: ${(a.strengths || []).join(', ')}
Weaknesses: ${(a.weaknesses || []).join(', ')}
Verdict: ${a.verdict || 'unknown'} (score: ${a.verdict_score || 0}/100)
Verdict Reasoning: ${a.verdict_reasoning || ''}

Top Videos:
${topVideos || '  (none)'}

Blue Ocean Opportunities:
${blueOcean || '  (none)'}

Content Saturation Map:
${saturation || '  (none)'}
`;
}).join('\n\n');

const systemPrompt = `You are an elite competitive landscape analyst specializing in YouTube niche strategy. You compare multiple channels to find the gaps, overlaps, and opportunities that no single channel analysis can reveal. You synthesize data across channels into actionable strategic insights. Be precise, data-driven, and specific. No generic advice.`;

const userPrompt = `Compare these ${analyses.length} YouTube channels as competitors in the same niche landscape.

${channelBlocks}

Synthesize a competitive landscape analysis. Return ONLY valid JSON with these exact fields:
{
  "combined_topic_landscape": [
    {"topic": "topic name", "covered_by": ["channel1", "channel2"], "coverage_depth": "deep/moderate/surface", "audience_demand": "high/medium/low"}
  ],
  "combined_blue_ocean_gaps": [
    {"gap": "description of underserved area", "evidence": "why we know it's underserved", "potential_impact": "high/medium/low", "difficulty": "easy/medium/hard"}
  ],
  "differentiation_strategy": {
    "positioning": "how a new channel should position against these competitors",
    "unique_angle": "the specific angle that none of these channels cover well",
    "content_format_recommendation": "recommended format (long-form doc, short explainer, etc)",
    "production_quality_bar": "minimum quality needed to compete"
  },
  "recommended_niche_description": "A 2-3 sentence niche description optimized for a new channel entering this space, incorporating the blue ocean gaps",
  "recommended_content_pillars": [
    {"pillar": "pillar name", "rationale": "why this pillar", "estimated_demand": "high/medium/low"},
    {"pillar": "pillar name", "rationale": "why this pillar", "estimated_demand": "high/medium/low"},
    {"pillar": "pillar name", "rationale": "why this pillar", "estimated_demand": "high/medium/low"},
    {"pillar": "pillar name", "rationale": "why this pillar", "estimated_demand": "high/medium/low"},
    {"pillar": "pillar name", "rationale": "why this pillar", "estimated_demand": "high/medium/low"}
  ],
  "overall_verdict": "strong_opportunity|moderate_opportunity|weak_opportunity|avoid",
  "overall_verdict_score": 75,
  "overall_verdict_reasoning": "2-4 sentences explaining the niche verdict based on competitive landscape"
}`;

