} catch (e) {
  return [{ json: { ...data, failed: true, error: `Exception: ${e.message}` } }];
}

// Log completion of channel comparison.

const data = $input.first().json;
if (data.failed) return [{ json: data }];

const supabaseUrl = $env.SUPABASE_URL;
const sbHeaders = {
  'apikey': $env.SUPABASE_ANON_KEY,
  'Authorization': `Bearer ${$env.SUPABASE_SERVICE_ROLE_KEY}`,
  'Content-Type': 'application/json'
};

try {
  await fetch(`${supabaseUrl}/rest/v1/production_logs`, {
    method: 'POST',
    headers: { ...sbHeaders, 'Prefer': 'return=minimal' },
    body: JSON.stringify({
      project_id: null,
      topic_id: null,
      stage: 'channel_compare',
      scene_number: null,
      action: 'completed',
      status: 'success',
      duration_ms: (data.comparison_duration_seconds || 0) * 1000,
      cost_usd: data.comparison_cost_usd || 0,
      retry_count: 0
    })
  });
} catch (_) {}

return [{ json: {
  success: true,
  report_id: data.report_id,
  analysis_group_id: data.analysis_group_id,
  analysis_count: data.analysis_count,
  cost_usd: data.comparison_cost_usd || 0
} }];
